mapper.select:
SELECT o.*, t.table_number, u.username
FROM orders o
LEFT JOIN table_info t ON o.table_id = t.table_id
LEFT JOIN `user` u ON o.user_id = u.user_id

    AND o.status = #{status}
    AND DATE(o.order_time) >= #{startDate}
    AND DATE(o.order_time) <= #{endDate}

ORDER BY o.order_id DESC

mapper.update:
UPDATE order_detail
SET quantity = quantity - #{quantity}
WHERE order_id = #{orderId}
  AND dish_id = #{dishId}
  AND quantity > #{quantity}

mapper.delete:
DELETE FROM order_detail
WHERE order_id = #{orderId}
  AND dish_id = #{dishId}
  AND quantity <= #{quantity}

mapper.update:
UPDATE orders
SET total_amount = GREATEST(total_amount - #{amount}, 0)
WHERE order_id = #{orderId}

UPDATE orders
SET paid_amount = #{paidAmount},
    discount_amount = #{discountAmount},
    pay_method = #{payMethod},
    pay_no = #{payNo}
WHERE order_id = #{orderId}

UPDATE order_detail
SET status = #{status}
WHERE order_id = #{orderId}
  AND dish_id = #{dishId}
